/**
 * GIF & Social Media Export Engine
 * Feature #77: GIF & Social Media Export
 *
 * Pure functions that generate FFmpeg command arguments for:
 * - Video → GIF conversion with quality/compression options
 * - Social media presets (Instagram Reels, TikTok, YouTube Shorts, etc.)
 * - Resolution/fps/bitrate configuration
 *
 * These functions do NOT call FFmpeg directly — they produce argument arrays
 * that the render worker can execute.
 */

import path from 'path';

// ─── GIF Types ─────────────────────────────────────────────────────────

export type GifQuality = 'low' | 'medium' | 'high';
export type GifDither = 'bayer' | 'floyd_steinberg' | 'none';

export interface GifExportOptions {
  readonly inputPath: string;
  readonly outputPath: string;
  readonly width: number;
  readonly fps: number;
  readonly quality: GifQuality;
  readonly loop: number;
  readonly startTime?: number;
  readonly duration?: number;
  readonly dither: GifDither;
}

// ─── Social Media Types ────────────────────────────────────────────────

export type SocialPlatform =
  | 'instagram_reel'
  | 'instagram_post'
  | 'instagram_story'
  | 'tiktok'
  | 'youtube_shorts'
  | 'youtube_standard'
  | 'twitter'
  | 'linkedin'
  | 'facebook'
  | 'whatsapp_status';

export type SocialCodec = 'h264' | 'h265';
export type SocialFormat = 'mp4' | 'webm';
export type CropPosition = 'center' | 'top' | 'bottom';
export type AspectRatioFilter = '16:9' | '9:16' | '1:1';

export interface SocialMediaPreset {
  readonly name: string;
  readonly platform: SocialPlatform;
  readonly width: number;
  readonly height: number;
  readonly maxDuration: number;
  readonly maxFileSize: number;
  readonly fps: number;
  readonly videoBitrate: string;
  readonly audioBitrate: string;
  readonly codec: SocialCodec;
  readonly format: SocialFormat;
  readonly aspectRatio: string;
  readonly label: string;
}

export interface SocialExportOptions {
  readonly inputPath: string;
  readonly outputPath: string;
  readonly preset: SocialMediaPreset;
  readonly crop?: CropPosition;
}

export interface ExportEstimate {
  readonly estimatedSizeMB: number;
  readonly estimatedDurationSeconds: number;
  readonly warnings: string[];
}

// ─── Constants ─────────────────────────────────────────────────────────

export const GIF_MAX_DURATION = 30;
export const GIF_MAX_WIDTH = 800;
export const GIF_MIN_WIDTH = 120;
export const GIF_MIN_FPS = 10;
export const GIF_MAX_FPS = 30;

// ─── Quality Multipliers (affects palette & dither quality) ────────────

const GIF_QUALITY_MULTIPLIERS: Record<GifQuality, number> = {
  low: 0.4,
  medium: 0.7,
  high: 1.0,
} as const;

