// ─── GIF FFmpeg Args Builder ───────────────────────────────────────────

/**
 * Build FFmpeg arguments for GIF conversion (two-pass palette method).
 * Returns two arrays: [palettePassArgs, gifPassArgs].
 *
 * Pass 1 generates a color palette optimized for the content.
 * Pass 2 uses the palette to produce a high-quality GIF.
 */
export function buildGifArgs(options: GifExportOptions): {
  paletteArgs: string[];
  gifArgs: string[];
  palettePath: string;
} {
  const errors = validateGifOptions(options);
  if (errors.length > 0) {
    throw new Error(`Invalid GIF options: ${errors.join('; ')}`);
  }

  const dir = path.dirname(options.outputPath);
  const palettePath = path.join(dir, `_palette_${Date.now()}.png`);

  const inputArgs = buildInputArgs(options.inputPath, options.startTime, options.duration);
  const scaleFilter = `fps=${options.fps},scale=${options.width}:-1:flags=lanczos`;

  // Palette stats mode based on quality
  const statsMode = options.quality === 'high' ? 'full' : 'diff';

  // Pass 1: Generate palette
  const paletteArgs: string[] = [
    ...inputArgs,
    '-vf',
    `${scaleFilter},palettegen=stats_mode=${statsMode}`,
    '-y',
    palettePath,
  ];

  // Dither filter string
  const ditherStr = options.dither === 'none'
    ? 'paletteuse=dither=none'
    : `paletteuse=dither=${options.dither === 'floyd_steinberg' ? 'floyd_steinberg' : 'bayer:bayer_scale=5'}`;

  // Pass 2: Generate GIF using palette
  const gifArgs: string[] = [
    ...inputArgs,
    '-i',
    palettePath,
    '-lavfi',
    `${scaleFilter}[x];[x][1:v]${ditherStr}`,
    '-loop',
    String(options.loop),
    '-y',
    options.outputPath,
  ];

  return { paletteArgs, gifArgs, palettePath };
}

// ─── Social Export FFmpeg Args Builder ──────────────────────────────────

/**
 * Build FFmpeg arguments for social media export.
 * Returns the full argument array for a single FFmpeg command.
 */
export function buildSocialExportArgs(options: SocialExportOptions): string[] {
  const errors = validateSocialOptions(options);
  if (errors.length > 0) {
    throw new Error(`Invalid social export options: ${errors.join('; ')}`);
  }

  const { preset, crop } = options;
  const args: string[] = ['-i', options.inputPath];

  // Build video filter chain
  const filters: string[] = [];

  // Scale + pad for aspect ratio handling
  if (crop) {
    const cropFilter = buildCropFilter(preset.width, preset.height, crop);
    filters.push(cropFilter);
  } else {
    filters.push(`scale=${preset.width}:${preset.height}:force_original_aspect_ratio=decrease`);
    filters.push(`pad=${preset.width}:${preset.height}:(ow-iw)/2:(oh-ih)/2:black`);
  }

  // FPS
  filters.push(`fps=${preset.fps}`);

  // Apply filters
  if (filters.length > 0) {
    args.push('-vf', filters.join(','));
  }

  // Video codec
  const codecName = preset.codec === 'h265' ? 'libx265' : 'libx264';
  args.push('-c:v', codecName);
  args.push('-b:v', preset.videoBitrate);
  args.push('-maxrate', preset.videoBitrate);

  // Buffer size (2x bitrate)
  const bitrateNum = parseBitrateToNumber(preset.videoBitrate);
  args.push('-bufsize', `${bitrateNum * 2}M`);

  // H.264 preset for compatibility
  if (preset.codec === 'h264') {
    args.push('-preset', 'medium');
    args.push('-profile:v', 'high');
    args.push('-level', '4.1');
    args.push('-pix_fmt', 'yuv420p');
  }

  // Audio
  args.push('-c:a', 'aac');
  args.push('-b:a', preset.audioBitrate);

  // Movflags for streaming
  args.push('-movflags', '+faststart');

  // Output
  args.push('-y', options.outputPath);

  return args;
}

// ─── Size Estimation ───────────────────────────────────────────────────

/**
 * Estimate GIF file size in MB.
 * Based on width, fps, duration, and quality multiplier.
 */
export function estimateGifSize(
  width: number,
  fps: number,
  durationSeconds: number,
  quality: GifQuality,
): number {
  // GIF size estimate: ~0.05 MB per frame at 320px width, scaling quadratically
  const widthFactor = (width / 320) ** 2;
  const qualityMultiplier = GIF_QUALITY_MULTIPLIERS[quality];
  const totalFrames = fps * durationSeconds;
  const baseSizePerFrame = 0.05;

  const estimated = totalFrames * baseSizePerFrame * widthFactor * qualityMultiplier;
  return Math.round(estimated * 100) / 100;
}

/**
 * Estimate social media export file size in MB.
 * Based on video bitrate, audio bitrate, and duration.
 */
export function estimateSocialSize(
  preset: SocialMediaPreset,
  durationSeconds: number,
): number {
  const videoBitrateMbps = parseBitrateToNumber(preset.videoBitrate);
  const audioBitrateKbps = parseInt(preset.audioBitrate.replace('k', ''), 10) || 128;

  // Size = (videoBitrate + audioBitrate) * duration / 8
  const videoSizeMB = (videoBitrateMbps * durationSeconds) / 8;
  const audioSizeMB = ((audioBitrateKbps / 1000) * durationSeconds) / 8;

  const total = videoSizeMB + audioSizeMB;
  return Math.round(total * 100) / 100;
}

// ─── Validation ────────────────────────────────────────────────────────

/**
 * Validate GIF export options. Returns array of error messages.
 * Empty array means valid.
 */
export function validateGifOptions(options: GifExportOptions): string[] {
  const errors: string[] = [];

  if (!options.inputPath || options.inputPath.trim() === '') {
    errors.push('inputPath is required');
  }
  if (!options.outputPath || options.outputPath.trim() === '') {
    errors.push('outputPath is required');
  }
  if (options.width < GIF_MIN_WIDTH || options.width > GIF_MAX_WIDTH) {
    errors.push(`width must be between ${GIF_MIN_WIDTH} and ${GIF_MAX_WIDTH}, got ${options.width}`);
  }
  if (options.fps < GIF_MIN_FPS || options.fps > GIF_MAX_FPS) {
    errors.push(`fps must be between ${GIF_MIN_FPS} and ${GIF_MAX_FPS}, got ${options.fps}`);
  }
  if (options.loop < 0) {
    errors.push('loop must be >= 0');
  }
  if (options.duration !== undefined && options.duration > GIF_MAX_DURATION) {
    errors.push(`duration must be <= ${GIF_MAX_DURATION}s, got ${options.duration}s`);
  }
  if (options.duration !== undefined && options.duration <= 0) {
    errors.push('duration must be > 0');
  }
  if (options.startTime !== undefined && options.startTime < 0) {
    errors.push('startTime must be >= 0');
  }

  const validQualities: GifQuality[] = ['low', 'medium', 'high'];
  if (!validQualities.includes(options.quality)) {
    errors.push(`quality must be one of: ${validQualities.join(', ')}`);
  }

  const validDithers: GifDither[] = ['bayer', 'floyd_steinberg', 'none'];
  if (!validDithers.includes(options.dither)) {
    errors.push(`dither must be one of: ${validDithers.join(', ')}`);
  }

  return errors;
}

/**
 * Validate social media export options. Returns array of error messages.
 * Empty array means valid.
 */
export function validateSocialOptions(options: SocialExportOptions): string[] {
  const errors: string[] = [];

  if (!options.inputPath || options.inputPath.trim() === '') {
    errors.push('inputPath is required');
  }
  if (!options.outputPath || options.outputPath.trim() === '') {
    errors.push('outputPath is required');
  }
  if (!options.preset) {
    errors.push('preset is required');
  } else {
    const validPlatforms = Object.keys(SOCIAL_PRESETS) as SocialPlatform[];
    if (!validPlatforms.includes(options.preset.platform)) {
      errors.push(`invalid platform: ${options.preset.platform}`);
    }
  }

  if (options.crop !== undefined) {
    const validCrops: CropPosition[] = ['center', 'top', 'bottom'];
    if (!validCrops.includes(options.crop)) {
      errors.push(`crop must be one of: ${validCrops.join(', ')}`);
    }
  }

  return errors;
}

// ─── Preset Accessors ──────────────────────────────────────────────────

/**
 * Get a social media preset by platform name.
 */
export function getPreset(platform: SocialPlatform): SocialMediaPreset {
  const preset = SOCIAL_PRESETS[platform];
  if (!preset) {
    throw new Error(`Unknown platform: ${platform}`);
  }
  return preset;
}

/**
 * List all available social media presets.
 */
export function listPresets(): SocialMediaPreset[] {
  return Object.values(SOCIAL_PRESETS);
}

/**
 * Get presets that match a specific aspect ratio.
 */
export function getPresetsForAspectRatio(ratio: AspectRatioFilter): SocialMediaPreset[] {
  return Object.values(SOCIAL_PRESETS).filter(
    (preset) => preset.aspectRatio === ratio,
  );
}

// ─── Export Estimation ─────────────────────────────────────────────────

/**
 * Estimate export result with size and warnings.
 */
export function estimateExport(
  options: { type: 'gif'; gifOptions: GifExportOptions } | { type: 'social'; socialOptions: SocialExportOptions; durationSeconds: number },
): ExportEstimate {
  const warnings: string[] = [];

  if (options.type === 'gif') {
    const { gifOptions } = options;
    const duration = gifOptions.duration ?? 10;
    const sizeMB = estimateGifSize(gifOptions.width, gifOptions.fps, duration, gifOptions.quality);

    if (sizeMB > 50) {
      warnings.push('Estimated GIF size exceeds 50 MB — consider reducing width, fps, or duration');
    }
    if (duration > 15) {
      warnings.push('GIFs longer than 15 seconds may be very large');
    }
    if (gifOptions.width > 600 && gifOptions.quality === 'high') {
      warnings.push('High quality at large width produces very large files');
    }

    return {
      estimatedSizeMB: sizeMB,
      estimatedDurationSeconds: duration,
      warnings,
    };
  }

  // Social export
  const { socialOptions, durationSeconds } = options;
  const sizeMB = estimateSocialSize(socialOptions.preset, durationSeconds);

  if (durationSeconds > socialOptions.preset.maxDuration) {
    warnings.push(
      `Duration (${durationSeconds}s) exceeds ${socialOptions.preset.name} max of ${socialOptions.preset.maxDuration}s`,
    );
  }
  if (sizeMB > socialOptions.preset.maxFileSize) {
    warnings.push(
      `Estimated size (${sizeMB} MB) exceeds ${socialOptions.preset.name} max of ${socialOptions.preset.maxFileSize} MB`,
    );
  }

  return {
    estimatedSizeMB: sizeMB,
    estimatedDurationSeconds: durationSeconds,
    warnings,
  };
}

// ─── Internal Helpers ──────────────────────────────────────────────────

function buildInputArgs(
  inputPath: string,
  startTime?: number,
  duration?: number,
): string[] {
  const args: string[] = [];

  if (startTime !== undefined && startTime > 0) {
    args.push('-ss', String(startTime));
  }
  if (duration !== undefined && duration > 0) {
    args.push('-t', String(duration));
  }

  args.push('-i', inputPath);

  return args;
}

function buildCropFilter(
  targetWidth: number,
  targetHeight: number,
  position: CropPosition,
): string {
  // Scale to fill target dimension, then crop
  const positionMap: Record<CropPosition, string> = {
    center: '(in_w-out_w)/2:(in_h-out_h)/2',
    top: '(in_w-out_w)/2:0',
    bottom: '(in_w-out_w)/2:in_h-out_h',
  };

  return `scale=${targetWidth}:${targetHeight}:force_original_aspect_ratio=increase,crop=${targetWidth}:${targetHeight}:${positionMap[position]}`;
}

function parseBitrateToNumber(bitrate: string): number {
  const match = bitrate.match(/^(\d+(?:\.\d+)?)([MmKk]?)$/);
  if (!match) return 5;

  const value = parseFloat(match[1]);
  const unit = match[2].toUpperCase();

  if (unit === 'K') return value / 1000;
  return value; // Already in M (or unitless, treated as M)
}
